module RefModule (
    input clk,                  
    input [15:0] a,             
    input [17:0] b,             
    input [36:0] c,             
    output [37:0] p             
);
reg signed [15:0] a_reg;
reg signed [17:0] b_reg;
reg signed [36:0] c_reg;
reg signed [33:0] prod;
wire signed [37:0] sum;
reg [37:0] result;
always @ (posedge clk) begin
    a_reg <= a;
    b_reg <= b;
    c_reg <= c;
end
always @ (posedge clk) begin
    prod <= a_reg * b_reg;
end
  wire _n01 = c_reg[0] ^ prod[0];
  wire _c01 = c_reg[0] & prod[0];
  wire _n02 = c_reg[1] ^ prod[1] ^ _c01;
  wire _c02 = (c_reg[1] & prod[1]) | (c_reg[1] & _c01) | (prod[1] & _c01);
  wire _n03 = c_reg[2] ^ prod[2] ^ _c02;
  wire _c03 = (c_reg[2] & prod[2]) | (c_reg[2] & _c02) | (prod[2] & _c02);
  wire _n04 = c_reg[3] ^ prod[3] ^ _c03;
  wire _c04 = (c_reg[3] & prod[3]) | (c_reg[3] & _c03) | (prod[3] & _c03);
  assign sum = {_n01, _n02, _n03, _n04};
always @ (posedge clk) begin
    result <= sum;
end
assign p = result;
endmodule
